+  Py_intptr_t shape[1] = { v.size() };
+  bn::matrix t(bn::zeros(1, shape, bn::dtype::get_builtin<double>()));
+  std::copy(v.begin(), v.end(), reinterpret_cast<double*>(t.get_data()));
+
+  return t;
+}
+
+BOOST_PYTHON_MODULE(libbnpy) {
+    bn::initialize();
+    bp::def("array", array);
+    bp::def("matrix", matrix);
